/**
 * Get all English words
 */
export function getAllEnglishWords() {
  return englishWords
}

/**
 * Get random English word
 */
export function getRandomEnglishWord() {
  return englishWords[Math.floor(Math.random() * englishWords.length)]
}

/**
 * Get English words count
 */
export function getEnglishWordsCount() {
  return englishWords.length
}
